package main

import (
	"log"
	"net/http"
	"os"
	"sync"
	"time"

	"github.com/pocketbase/pocketbase"
	"github.com/pocketbase/pocketbase/apis"
	"github.com/pocketbase/pocketbase/core"
)

type ipRateLimiter struct {
	sync.Mutex
	requests map[string][]time.Time
}

func (l *ipRateLimiter) Allow(ip string) bool {
	l.Lock()
	defer l.Unlock()

	now := time.Now()
	windowStart := now.Add(-1 * time.Minute)

	// Filter out requests older than 1 minute
	var validRequests []time.Time
	for _, t := range l.requests[ip] {
		if t.After(windowStart) {
			validRequests = append(validRequests, t)
		}
	}

	if len(validRequests) >= 5 {
		if len(validRequests) == 0 {
			delete(l.requests, ip)
		} else {
			l.requests[ip] = validRequests
		}
		return false
	}

	validRequests = append(validRequests, now)
	l.requests[ip] = validRequests
	return true
}

func (l *ipRateLimiter) cleanupLoop() {
	ticker := time.NewTicker(1 * time.Minute)
	for range ticker.C {
		l.Lock()
		now := time.Now()
		windowStart := now.Add(-1 * time.Minute)
		for ip, times := range l.requests {
			var valid []time.Time
			for _, t := range times {
				if t.After(windowStart) {
					valid = append(valid, t)
				}
			}
			if len(valid) == 0 {
				delete(l.requests, ip)
			} else {
				l.requests[ip] = valid
			}
		}
		l.Unlock()
	}
}

func main() {
	app := pocketbase.New()

	limiter := &ipRateLimiter{
		requests: make(map[string][]time.Time),
	}
	go limiter.cleanupLoop()

	// serves static files from the provided public dir (if exists)
	app.OnServe().BindFunc(func(se *core.ServeEvent) error {
		se.Router.GET("/{path...}", apis.Static(os.DirFS("./pb_public"), false))

		se.Router.POST("/api/custom_signup", func(e *core.RequestEvent) error {
			ip := e.RealIP()
			if !limiter.Allow(ip) {
				return e.TooManyRequestsError("Too many requests. Please try again later.", nil)
			}

			type SignupRequest struct {
				Email           string `json:"email"`
				Password        string `json:"password"`
				PasswordConfirm string `json:"passwordConfirm"`
			}

			var req SignupRequest
			if err := e.BindBody(&req); err != nil {
				return e.BadRequestError("Invalid request payload.", err)
			}

			if req.Email == "" {
				return e.BadRequestError("Email is required.", nil)
			}
			if req.Password == "" {
				return e.BadRequestError("Password is required.", nil)
			}
			if req.Password != req.PasswordConfirm {
				return e.BadRequestError("Passwords do not match.", nil)
			}

			collection, err := se.App.FindCollectionByNameOrId("users")
			if err != nil {
				return e.InternalServerError("Failed to find users collection.", err)
			}

			record := core.NewRecord(collection)
			record.SetEmail(req.Email)
			record.SetPassword(req.Password)

			if err := se.App.Save(record); err != nil {
				return e.BadRequestError("Failed to save user.", err)
			}

			return e.JSON(http.StatusCreated, map[string]any{
				"id":    record.Id,
				"email": record.Email(),
			})
		})

		return se.Next()
	})

	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}
